(13895, 2449, 'alternative_titles', 'a:12:{i:0;s:29:\"The Super Mario Bros. Movie 2\";i:1;s:21:\"Super Mario Dünyası\";i:2;s:17:\"Super Mario World\";i:3;s:40:\"האחים סופר מריו: גלקסי\";i:4;s:18:\"Super Mario Galaxy\";i:5;s:21:\"Super Mario Galaktika\";i:6;s:27:\"Super Mario Galatički Film\";i:7;s:32:\"Super Mario Galaxy: La película\";i:8;s:27:\"SUPER MARIO GALAXY, LE FILM\";i:9;s:99:\"เดอะ ซูเปอร์มาริโอ กาแล็กซี่ มูฟวี่\";i:10;s:60:\"ザ・スーパーマリオギャラクシー・ムービー\";i:11;s:25:\"슈퍼마리오 갤럭시\";}'),
