(14702, 2625, 'alternative_titles', 'a:18:{i:0;s:12:\"Mo\'adon Krav\";i:1;s:15:\"Borilački klub\";i:2;s:16:\"Boytsovskiy klub\";i:3;s:9:\"Boen klub\";i:4;s:18:\"Biytsivsʹkyy klub\";i:5;s:27:\"Байцоўскі клюб\";i:6;s:14:\"Döyüş Klubu\";i:7;s:49:\"მალჷმორეფიშ კლუბი\";i:8;s:29:\"Մարտական ակումբ\";i:9;s:30:\"النادي د لمدابزة\";i:10;s:21:\"نادى القتال\";i:11;s:23:\"Мушташ клубу\";i:12;s:17:\"فایت کلاب\";i:13;s:25:\"फाइट क्लब\";i:14;s:28:\"ਫ਼ਾਈਟ ਕਲੱਬ\";i:15;s:9:\"搏击会\";i:16;s:15:\"鬥陣俱樂部\";i:17;s:21:\"Մարտ Ակումբ\";}'),
