(3056, 1, '2026-04-17 16:33:58', '2026-04-17 16:33:58', 'Rachel is a criminology student hoping to land a position as a teacher\'s assistant for professor Robert Starkman. She\'s sure this position will pave the way to an FBI career, and she\'s willing to do anything to obtain it -- including killing her classmates. The school psychiatrist, Dr. Daniels, becomes aware that Rachel is insane, but Rachel is skilled at her dangerous game of death and identity theft.', 'American Psycho II: All American Girl', '', 'publish', 'closed', 'closed', '', 'american-psycho-ii-all-american-girl', '', '', '2026-04-17 16:33:58', '2026-04-17 16:33:58', '', 0, 'http://localhost/jobsity/movies/american-psycho-ii-all-american-girl/', 0, 'movie', '', 0),
(3057, 1, '2026-04-17 16:34:00', '2026-04-17 16:34:00', '', 'mYBvrIV78mckZGdT5gpHtXOKVc2', '', 'inherit', 'open', 'closed', '', 'mybvriv78mckzgdt5gphtxokvc2', '', '', '2026-04-17 16:34:00', '2026-04-17 16:34:00', '', 3056, 'http://localhost/jobsity/wp-content/uploads/2026/04/mYBvrIV78mckZGdT5gpHtXOKVc2.jpg', 0, 'attachment', 'image/jpeg', 0),
(3058, 1, '2026-04-17 16:34:01', '2026-04-17 16:34:01', 'A post-apocalyptic tale, in which a lone man fights his way across America in order to protect a sacred book that holds the secrets to saving humankind.', 'The Book of Eli', '', 'publish', 'closed', 'closed', '', 'the-book-of-eli', '', '', '2026-04-17 16:34:01', '2026-04-17 16:34:01', '', 0, 'http://localhost/jobsity/movies/the-book-of-eli/', 0, 'movie', '', 0);
INSERT INTO `wp_jobsity_posts` (`ID`, `post_author`, `post_date`, `post_date_gmt`, `post_content`, `post_title`, `post_excerpt`, `post_status`, `comment_status`, `ping_status`, `post_password`, `post_name`, `to_ping`, `pinged`, `post_modified`, `post_modified_gmt`, `post_content_filtered`, `post_parent`, `guid`, `menu_order`, `post_type`, `post_mime_type`, `comment_count`) VALUES
(3059, 1, '2026-04-17 16:34:02', '2026-04-17 16:34:02', '', '1H1y9ZiqNFaLgQiRDDZLA55PviW', '', 'inherit', 'open', 'closed', '', '1h1y9ziqnfalgqirddzla55pviw', '', '', '2026-04-17 16:34:02', '2026-04-17 16:34:02', '', 3058, 'http://localhost/jobsity/wp-content/uploads/2026/04/1H1y9ZiqNFaLgQiRDDZLA55PviW.jpg', 0, 'attachment', 'image/jpeg', 0),
(3060, 1, '2026-04-17 16:34:05', '2026-04-17 16:34:05', 'Thomas Jeffrey Hanks (born July 9, 1956) is an American actor and filmmaker. Known for both his comedic and dramatic roles, Hanks is one of the most popular and recognizable film stars worldwide, and is widely regarded as an American cultural icon.\n\nHanks made his breakthrough with leading roles in the comedies Splash (1984) and Big (1988). He won two consecutive Academy Awards for Best Actor for starring as a gay lawyer suffering from AIDS in Philadelphia (1993) and a young man with below-average IQ in Forrest Gump (1994). Hanks collaborated with film director Steven Spielberg on five films: Saving Private Ryan (1998), Catch Me If You Can (2002), The Terminal (2004), Bridge of Spies (2015), and The Post (2017), as well as the 2001 miniseries Band of Brothers, which launched him as a director, producer, and screenwriter.\n\nHanks\' other notable films include the romantic comedies Sleepless in Seattle (1993) and You\'ve Got Mail (1998); the dramas Apollo 13 (1995), The Green Mile (1999), Cast Away (2000), Road to Perdition (2002), and Cloud Atlas (2012); and the biographical dramas Saving Mr. Banks (2013), Captain Phillips (2013), Sully (2016), and A Beautiful Day in the Neighborhood (2019). He has also appeared as the title character in the Robert Langdon film series, and has voiced Sheriff Woody in the Toy Story film series.\n\nDescription above from the Wikipedia article Tom Hanks, licensed under CC-BY-SA, full list of contributors on Wikipedia.', 'Tom Hanks', '', 'publish', 'closed', 'closed', '', 'tom-hanks', '', '', '2026-04-17 16:34:05', '2026-04-17 16:34:05', '', 0, 'http://localhost/jobsity/actors/tom-hanks/', 0, 'actor', '', 0),
(3061, 1, '2026-04-17 16:34:07', '2026-04-17 16:34:07', '', 'oFvZoKI6lvU03n4YoNGAll9rkas-4', '', 'inherit', 'open', 'closed', '', 'ofvzoki6lvu03n4yongall9rkas-4', '', '', '2026-04-17 16:34:07', '2026-04-17 16:34:07', '', 3060, 'http://localhost/jobsity/wp-content/uploads/2026/04/oFvZoKI6lvU03n4YoNGAll9rkas-4.jpg', 0, 'attachment', 'image/jpeg', 0),
(3062, 1, '2026-04-17 16:34:08', '2026-04-17 16:34:08', 'A man with a low IQ has accomplished great things in his life and been present during significant historic events—in each case, far exceeding what anyone imagined he could do. But despite all he has achieved, his one true love eludes him.', 'Forrest Gump', '', 'publish', 'closed', 'closed', '', 'forrest-gump', '', '', '2026-04-17 16:34:08', '2026-04-17 16:34:08', '', 0, 'http://localhost/jobsity/movies/forrest-gump/', 0, 'movie', '', 0),
(3063, 1, '2026-04-17 16:34:09', '2026-04-17 16:34:09', '', 'saHP97rTPS5eLmrLQEcANmKrsFl-3', '', 'inherit', 'open', 'closed', '', 'sahp97rtps5elmrlqecanmkrsfl-3', '', '', '2026-04-17 16:34:09', '2026-04-17 16:34:09', '', 3062, 'http://localhost/jobsity/wp-content/uploads/2026/04/saHP97rTPS5eLmrLQEcANmKrsFl-3.jpg', 0, 'attachment', 'image/jpeg', 0),
(3064, 1, '2026-04-17 16:34:10', '2026-04-17 16:34:10', 'After Homer accidentally pollutes the town\'s water supply, Springfield is encased in a gigantic dome by the EPA and the Simpsons are declared fugitives.', 'The Simpsons Movie', '', 'publish', 'closed', 'closed', '', 'the-simpsons-movie', '', '', '2026-04-17 16:34:10', '2026-04-17 16:34:10', '', 0, 'http://localhost/jobsity/movies/the-simpsons-movie/', 0, 'movie', '', 0),
(3065, 1, '2026-04-17 16:34:12', '2026-04-17 16:34:12', '', 's3b8TZWwmkYc2KoJ5zk77qB6PzY-3', '', 'inherit', 'open', 'closed', '', 's3b8tzwwmkyc2koj5zk77qb6pzy-3', '', '', '2026-04-17 16:34:12', '2026-04-17 16:34:12', '', 3064, 'http://localhost/jobsity/wp-content/uploads/2026/04/s3b8TZWwmkYc2KoJ5zk77qB6PzY-3.jpg', 0, 'attachment', 'image/jpeg', 0),
(3066, 1, '2026-04-17 16:34:13', '2026-04-17 16:34:13', 'As U.S. troops storm the beaches of Normandy, three brothers lie dead on the battlefield, with a fourth trapped behind enemy lines. Ranger captain John Miller and seven men are tasked with penetrating German-held territory and bringing the boy home.', 'Saving Private Ryan', '', 'publish', 'closed', 'closed', '', 'saving-private-ryan', '', '', '2026-04-17 16:34:13', '2026-04-17 16:34:13', '', 0, 'http://localhost/jobsity/movies/saving-private-ryan/', 0, 'movie', '', 0),
(3067, 1, '2026-04-17 16:34:14', '2026-04-17 16:34:14', '', 'uqx37cS8cpHg8U35f9U5IBlrCV3-1', '', 'inherit', 'open', 'closed', '', 'uqx37cs8cphg8u35f9u5iblrcv3-1', '', '', '2026-04-17 16:34:14', '2026-04-17 16:34:14', '', 3066, 'http://localhost/jobsity/wp-content/uploads/2026/04/uqx37cS8cpHg8U35f9U5IBlrCV3-1.jpg', 0, 'attachment', 'image/jpeg', 0),
(3068, 1, '2026-04-17 16:34:17', '2026-04-17 16:34:17', 'Christy Shae Marks (born June 1, 1972) is an American model and actress of Cherokee, Irish, and French heritage.\n\nShae Marks was born in New Orleans, Louisiana where she spent most of childhood. According to her Playmate Profile, she was a tomboy growing up. Soon after her tenth birthday, Marks\'s family moved to Peachtree City, Georgia, a suburb of Atlanta. While in high school she played soccer and tennis and was involved in swimming and cheerleading. After graduating from McIntosh high school, she briefly majored in journalism at the University of West Georgia, but later dropped out and moved back to New Orleans.\n\nShae Marks was discovered by Playboy when she was 20 years old at the World Gym in Houston, Texas. One month later, in October 1993, she flew to Los Angeles, California (meeting her husband on the flight), did a test shoot for a centerfold and was accepted as Playmate of the Month for May 1994. During her stint with Playboy, Marks was a traveling representative for the company, visiting such ports of call as Hong Kong and Denmark. Later she entered the acting arena, guest starring on such shows as Married... with Children, Renegade, Viper, and Baywatch. Marks was also featured in advertisements for Molson Beer, as well as modeling for Frederick’s of Hollywood, Venus Swimwear, and other catalogs.', 'Shae Marks', '', 'publish', 'closed', 'closed', '', 'shae-marks', '', '', '2026-04-17 16:34:17', '2026-04-17 16:34:17', '', 0, 'http://localhost/jobsity/actors/shae-marks/', 0, 'actor', '', 0),
(3069, 1, '2026-04-17 16:34:18', '2026-04-17 16:34:18', '', 'jYBVCrSyi7T98ofuD0jSWcr1qrx-4', '', 'inherit', 'open', 'closed', '', 'jybvcrsyi7t98ofud0jswcr1qrx-4', '', '', '2026-04-17 16:34:18', '2026-04-17 16:34:18', '', 3068, 'http://localhost/jobsity/wp-content/uploads/2026/04/jYBVCrSyi7T98ofuD0jSWcr1qrx-4.jpg', 0, 'attachment', 'image/jpeg', 0),
(3070, 1, '2026-04-17 16:34:20', '2026-04-17 16:34:20', 'Get ready for excitement with Playboy\'s spectacular tribute to well-endowed women.', 'Playboy\'s Voluptuous Vixens', '', 'publish', 'closed', 'closed', '', 'playboys-voluptuous-vixens', '', '', '2026-04-17 16:34:20', '2026-04-17 16:34:20', '', 0, 'http://localhost/jobsity/movies/playboys-voluptuous-vixens/', 0, 'movie', '', 0),
(3071, 1, '2026-04-17 16:34:21', '2026-04-17 16:34:21', '', 'gnWtGKHBwLwljZMfIcPkNSbLrN2-3', '', 'inherit', 'open', 'closed', '', 'gnwtgkhbwlwljzmficpknsblrn2-3', '', '', '2026-04-17 16:34:21', '2026-04-17 16:34:21', '', 3070, 'http://localhost/jobsity/wp-content/uploads/2026/04/gnWtGKHBwLwljZMfIcPkNSbLrN2-3.jpg', 0, 'attachment', 'image/jpeg', 0),
(3072, 1, '2026-04-17 16:34:22', '2026-04-17 16:34:22', 'Cop by day, masked crusader by night, the fearless and sultry Black Scorpion must protect the City of Angels from a deadly trio of villains... the prosthetic machine gun Firearm, the time-controlling Clockwise, and vision-stealing Flashpoint.', 'Sting of the Black Scorpion', '', 'publish', 'closed', 'closed', '', 'sting-of-the-black-scorpion', '', '', '2026-04-17 16:34:22', '2026-04-17 16:34:22', '', 0, 'http://localhost/jobsity/movies/sting-of-the-black-scorpion/', 0, 'movie', '', 0),
